// src/api.js
// Centralised fetch calls to the Flask backend

const BASE = process.env.REACT_APP_API_URL || '';

async function get(path, params = {}) {
  const qs = new URLSearchParams(
    Object.fromEntries(Object.entries(params).filter(([, v]) => v !== '' && v != null))
  ).toString();
  const url = `${BASE}${path}${qs ? '?' + qs : ''}`;
  const res = await fetch(url);
  if (!res.ok) throw new Error(`API ${res.status}: ${url}`);
  return res.json();
}

export const fetchFilters  = ()       => get('/api/filters');
export const fetchMetrics  = (params) => get('/api/metrics', params);
export const fetchPlayers  = (params) => get('/api/players', params);
export const fetchBirthChart = ()     => get('/api/charts/birthyear');
export const fetchPlayer   = (id)     => get(`/api/player/${id}`);
// Append this to the bottom of your src/api.js file

export async function fetchTeamFilters() {
  try {
    // If your backend endpoint is different, update this URL path
    const res = await fetch('/api/filters/teams'); 
    if (!res.ok) throw new Error('Could not fetch team dropdown options');
    return await res.json();
  } catch (err) {
    console.error(err);
    // Safe fallback object to prevent app crashes if backend fails
    return { leagues: [] }; 
  }
}

export async function fetchTeams(params) {
  try {
    const query = new URLSearchParams(params).toString();
    // If your backend endpoint is different, update this URL path
    const res = await fetch(`/api/teams?${query}`); 
    if (!res.ok) throw new Error('Could not fetch filtered team list');
    return await res.json();
  } catch (err) {
    console.error(err);
    // Safe fallback structure matching state definitions
    return { data: [], total: 0, query: 'SELECT * FROM teams LIMIT 50;' }; 
  }
}
